import { tailwindPlugin } from "@hushkey/howl/plugins";

const builder = new HowlBuilder(app, { /* ... */ });

tailwindPlugin(builder.getBuilder("default")!, {
  exclude: ["/vendor/**"], // optional: skip paths/globs
});

import { tailwindConfigBase } from "@hushkey/howl/plugins";

export default {
  ...tailwindConfigBase,
  // your overrides
};

import { httpClientGenPlugin } from "@hushkey/howl/plugins";

const builder = new HowlBuilder(app, {
  plugins: [
    /* engine plugin */
    httpClientGenPlugin({
      apiDir: "server/apis",
      outputFile: "./generated/http-client.ts",
      aliases: { "@server/": "server/" },
    }),
  ],
});

import { http } from "../generated/http-client.ts";

// GET /api/public/ping
const ping = await http.api.public.ping.$get();
console.log(ping.ok, ping.message);

// POST /api/users/create  (body is typed from the Zod requestBody)
const res = await http.api.users.create.$post({
  body: { email: "a@b.com", name: "Ada" },
});
